&lt;p style=&quot;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&amp;#39;x&amp;#39; से &amp;#39;y&amp;#39; का अनुपात&amp;nbsp;&lt;/font&gt;&lt;span class=&quot;math-tex&quot;&gt;\(\frac{x}{y}\)&lt;/span&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&amp;nbsp;&lt;/font&gt;&lt;span style=&quot;&quot;&gt;है&lt;/span&gt;&lt;span style=&quot;color: rgb(77, 81, 86); &quot;&gt;।&lt;/span&gt;&lt;/p&gt;

&lt;p style=&quot;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;गणना:&lt;/span&gt;&lt;/p&gt;

&lt;p style=&quot;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;दिए गए वृत्त आरेख से,&amp;nbsp;&lt;/font&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;व्यक्ति द्वारा भोजन पर किए गए व्यय का प्रतिशत 15% है और&amp;nbsp;व्यक्ति द्वारा किराए पर किए गए व्यय का प्रतिशत 20% है&lt;/font&gt;&lt;span style=&quot;color: rgb(77, 81, 86);  &quot;&gt;।&lt;/span&gt;&lt;/p&gt;

&lt;p style=&quot;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;और&amp;nbsp;&lt;/font&gt;&lt;span class=&quot;math-tex&quot;&gt;\(\frac{15}{20}=\frac{3}{4}\)&lt;/span&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;.&lt;/font&gt;&lt;/p&gt;

